1	import { QueryClient, QueryClientProvider } from "@tanstack/react-query";
2	import { MemoryRouter } from "react-router-dom";
3	import { SessionProvider } from "@/features/session/context";
4	import { routerFuture } from "@/app/routerFuture";
5	import { render, type RenderOptions } from "@testing-library/react";
6	import type { ReactElement, ReactNode } from "react";
7	
8	function createTestQueryClient() {
9	  return new QueryClient({
10	    defaultOptions: {
11	      queries: { retry: false, gcTime: 0 },
12	      mutations: { retry: false },
13	    },
14	  });
15	}
16	
17	function TestProviders({
18	  children,
19	  initialEntries,
20	}: {
21	  children: ReactNode;
22	  initialEntries?: string[];
23	}) {
24	  const qc = createTestQueryClient();
25	  return (
26	    <QueryClientProvider client={qc}>
27	      <SessionProvider>
28	        <MemoryRouter future={routerFuture} initialEntries={initialEntries}>
29	          {children}
30	        </MemoryRouter>
31	      </SessionProvider>
32	    </QueryClientProvider>
33	  );
34	}
35	
36	export function renderWithProviders(
37	  ui: ReactElement,
38	  options?: Omit<RenderOptions, "wrapper"> & { route?: string; initialEntries?: string[] },
39	) {
40	  const { route, initialEntries, ...renderOptions } = options ?? {};
41	
42	  function Wrapper({ children }: { children: ReactNode }) {
43	    return (
44	      <TestProviders initialEntries={initialEntries ?? (route ? [route] : undefined)}>
45	        {children}
46	      </TestProviders>
47	    );
48	  }
49	
50	  return render(ui, { wrapper: Wrapper, ...renderOptions });
51	}
